#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    if(n == 0){
        cout << 0 << endl;
    } else {
        int i = 0;
        for(int j = 1; j < n; j++){
            if(nums[j] != nums[i]){
                i += 1;
                nums[i] = nums[j];
            }
        }
        cout << i + 1 << endl;
    }
    return 0;
}
